class Solution:
    def maximumXorProduct(self, a: int, b: int, n: int) -> int:
        MOD = 10**9 + 7
        x = 0
        for i in range(n-1, -1, -1):
            bit = 1 << i
            # Try setting this bit to 1
            x_candidate = x | bit
            a_candidate = a ^ x_candidate
            b_candidate = b ^ x_candidate
            if a_candidate * b_candidate > (a ^ x) * (b ^ x):
                x = x_candidate
        return ((a ^ x) * (b ^ x)) % MOD
